namespace sv_9c4162e87559400ab47c3368802546c0.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@using sv_9c4162e87559400ab47c3368802546c0.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<div class="catalog-container">
    <!-- Left Sidebar -->
    <aside class="catalog-sidebar">
        <h3>Filters</h3>

        <div class="filter-section">
            <h4>Categories</h4>
            @if (categories is not null)
            {
                @foreach (var category in categories)
                {
                    <label class="filter-checkbox">
                        <input type="checkbox"
                               checked="@selectedCategories.Contains(category)"
                               @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                        @category
                    </label>
                }
            }
            else
            {
                <p class="loading-text">Loading categories…</p>
            }
        </div>

        <div class="filter-section">
            <h4>Price Range</h4>
            <div class="price-inputs">
                <label>
                    Min
                    <input type="number" min="0" step="0.01" @bind="minPrice" placeholder="Min" />
                </label>
                <label>
                    Max
                    <input type="number" min="0" step="0.01" @bind="maxPrice" placeholder="Max" />
                </label>
            </div>
        </div>

        <div class="filter-section">
            <label class="filter-checkbox">
                <input type="checkbox" @bind="inStockOnly" />
                In Stock Only
            </label>
        </div>

        <div class="filter-actions">
            <button class="btn btn-primary" @onclick="ApplyFilters">Apply Filters</button>
            <button class="btn btn-secondary" @onclick="ClearFilters">Clear Filters</button>
        </div>
    </aside>

    <!-- Main Content -->
    <main class="catalog-main">
        @if (errorMessage is not null)
        {
            <div class="alert alert-error">
                <p>⚠ @errorMessage</p>
                <button class="btn btn-secondary" @onclick="RetryLoad">Retry</button>
            </div>
        }
        else
        {
            <!-- Toolbar -->
            <div class="catalog-toolbar">
                <div class="sort-control">
                    <label for="sort-select">Sort by:</label>
                    <select id="sort-select" @bind="sortBy" @bind:after="OnSortChanged">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A-Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <div class="results-summary">
                    @if (result is not null && result.TotalCount > 0)
                    {
                        var first = (result.Page - 1) * result.PageSize + 1;
                        var last = Math.Min(result.Page * result.PageSize, result.TotalCount);
                        <span>Showing @first–@last of @result.TotalCount products</span>
                    }
                </div>
            </div>

            @if (isLoading)
            {
                <div class="loading-container">
                    <p class="loading-text">Loading products…</p>
                </div>
            }
            else if (result is null || result.TotalCount == 0)
            {
                <div class="empty-state">
                    <p>No products found matching your filters.</p>
                    <button class="btn btn-secondary" @onclick="ClearFilters">Clear Filters</button>
                </div>
            }
            else
            {
                <!-- Product Grid -->
                <div class="product-grid">
                    @foreach (var product in result.Items)
                    {
                        <div class="product-card" @onclick="() => OnProductSelected(product.Id)" tabindex="0">
                            <div class="product-image" title="@product.Name">
                                @product.Name
                            </div>
                            <div class="product-info">
                                <h4 class="product-name">@product.Name</h4>
                                <p class="product-price">@product.Price.ToString("C")</p>
                                <p class="product-rating">@GetStarRating(product.Rating)</p>
                                @if (!product.InStock)
                                {
                                    <span class="badge badge-out-of-stock">Out of Stock</span>
                                }
                                <button class="btn btn-cart"
                                        disabled="@(!product.InStock)"
                                        @onclick="() => { }"
                                        @onclick:stopPropagation="true">
                                    Add to Cart
                                </button>
                            </div>
                        </div>
                    }
                </div>

                <!-- Pagination -->
                <nav class="pagination" aria-label="Product pagination">
                    <button class="btn btn-page"
                            disabled="@(currentPage <= 1)"
                            @onclick="() => GoToPage(currentPage - 1)">
                        Previous
                    </button>

                    @for (var i = 1; i <= TotalPages; i++)
                    {
                        var page = i;
                        <button class="btn btn-page @(page == currentPage ? "active" : "")"
                                @onclick="() => GoToPage(page)">
                            @page
                        </button>
                    }

                    <button class="btn btn-page"
                            disabled="@(currentPage >= TotalPages)"
                            @onclick="() => GoToPage(currentPage + 1)">
                        Next
                    </button>
                </nav>
            }
        }
    </main>
</div>

@code {
    [Parameter] public EventCallback<int> OnProductClicked { get; set; }

    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 12;

    private PagedResult<Product>? result;
    private bool isLoading;
    private string? errorMessage;

    private int TotalPages => result is null || result.PageSize == 0
        ? 1
        : (int)Math.Ceiling((double)result.TotalCount / result.PageSize);

    protected override async Task OnInitializedAsync()
    {
        await LoadCategoriesAndProducts();
    }

    private async Task LoadCategoriesAndProducts()
    {
        try
        {
            errorMessage = null;
            isLoading = true;

            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = LoadProducts();

            await Task.WhenAll(categoriesTask, productsTask);

            categories = await categoriesTask;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load catalog: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task LoadProducts()
    {
        try
        {
            errorMessage = null;
            isLoading = true;

            var filter = new ProductFilter(
                Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
                MinPrice: minPrice,
                MaxPrice: maxPrice,
                InStockOnly: inStockOnly
            );

            result = await ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load products: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await LoadProducts();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        await LoadProducts();
    }

    private async Task OnSortChanged()
    {
        currentPage = 1;
        await LoadProducts();
    }

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > TotalPages) return;
        currentPage = page;
        await LoadProducts();
    }

    private async Task OnProductSelected(int productId)
    {
        await OnProductClicked.InvokeAsync(productId);
    }

    private async Task RetryLoad()
    {
        await LoadCategoriesAndProducts();
    }

    private static string GetStarRating(double rating)
    {
        var fullStars = (int)Math.Round(rating);
        var emptyStars = 5 - fullStars;
        return new string('★', fullStars) + new string('☆', emptyStars);
    }
}

.catalog-container {
    display: flex;
    gap: 1.5rem;
    padding: 1rem;
    max-width: 1400px;
    margin: 0 auto;
}

/* Sidebar */
.catalog-sidebar {
    width: 25%;
    min-width: 220px;
    flex-shrink: 0;
    background: #f8f9fa;
    border-radius: 8px;
    padding: 1.25rem;
    align-self: flex-start;
}

.catalog-sidebar h3 {
    margin: 0 0 1rem;
    font-size: 1.25rem;
}

.filter-section {
    margin-bottom: 1.25rem;
}

.filter-section h4 {
    margin: 0 0 0.5rem;
    font-size: 0.95rem;
    color: #555;
}

.filter-checkbox {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    margin-bottom: 0.35rem;
    cursor: pointer;
    font-size: 0.9rem;
}

.price-inputs {
    display: flex;
    gap: 0.5rem;
}

.price-inputs label {
    display: flex;
    flex-direction: column;
    font-size: 0.85rem;
    flex: 1;
}

.price-inputs input {
    padding: 0.35rem 0.5rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    margin-top: 0.2rem;
    width: 100%;
    box-sizing: border-box;
}

.filter-actions {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

/* Buttons */
.btn {
    padding: 0.5rem 1rem;
    border: none;
    border-radius: 6px;
    cursor: pointer;
    font-size: 0.9rem;
    transition: opacity 0.15s;
}

.btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.btn-primary {
    background: #0d6efd;
    color: #fff;
}

.btn-primary:hover:not(:disabled) {
    background: #0b5ed7;
}

.btn-secondary {
    background: #6c757d;
    color: #fff;
}

.btn-secondary:hover:not(:disabled) {
    background: #5c636a;
}

/* Main content */
.catalog-main {
    flex: 1;
    min-width: 0;
}

.catalog-toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1rem;
    flex-wrap: wrap;
    gap: 0.75rem;
}

.sort-control {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.sort-control select {
    padding: 0.4rem 0.6rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 0.9rem;
}

.results-summary {
    font-size: 0.9rem;
    color: #666;
}

/* Product grid */
.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 1rem;
}

.product-card {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    cursor: pointer;
    transition: box-shadow 0.2s, transform 0.15s;
    display: flex;
    flex-direction: column;
    background: #fff;
}

.product-card:hover {
    box-shadow: 0 4px 16px rgba(0,0,0,0.1);
    transform: translateY(-2px);
}

.product-image {
    background: #e9ecef;
    height: 160px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 0.85rem;
    color: #888;
    padding: 0.5rem;
    text-align: center;
}

.product-info {
    padding: 0.75rem;
    display: flex;
    flex-direction: column;
    gap: 0.3rem;
    flex: 1;
}

.product-name {
    margin: 0;
    font-size: 1rem;
    font-weight: 600;
}

.product-price {
    margin: 0;
    font-size: 1.05rem;
    color: #198754;
    font-weight: 600;
}

.product-rating {
    margin: 0;
    color: #ffc107;
    font-size: 1.1rem;
    letter-spacing: 1px;
}

.badge {
    display: inline-block;
    padding: 0.2rem 0.5rem;
    border-radius: 4px;
    font-size: 0.75rem;
    font-weight: 600;
    width: fit-content;
}

.badge-out-of-stock {
    background: #dc3545;
    color: #fff;
}

.btn-cart {
    margin-top: auto;
    background: #198754;
    color: #fff;
    width: 100%;
}

.btn-cart:hover:not(:disabled) {
    background: #157347;
}

/* Pagination */
.pagination {
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 0.35rem;
    margin-top: 1.5rem;
    flex-wrap: wrap;
}

.btn-page {
    min-width: 2.5rem;
    padding: 0.4rem 0.75rem;
    background: #fff;
    border: 1px solid #dee2e6;
    color: #333;
}

.btn-page:hover:not(:disabled):not(.active) {
    background: #e9ecef;
}

.btn-page.active {
    background: #0d6efd;
    color: #fff;
    border-color: #0d6efd;
}

/* States */
.loading-container,
.empty-state {
    text-align: center;
    padding: 3rem 1rem;
    color: #666;
}

.loading-text {
    color: #888;
    font-style: italic;
}

.alert {
    padding: 1rem;
    border-radius: 8px;
    margin-bottom: 1rem;
}

.alert-error {
    background: #f8d7da;
    color: #842029;
    border: 1px solid #f5c2c7;
}

.alert-error .btn {
    margin-top: 0.75rem;
}

